    cin.tie(0);
#define endl '\n'
#define f first
#define s second

typedef unsigned long long llu;
typedef unsigned int ui;
typedef long long ll;

int main()
{
    //_
    string entrada;
    int ninho = 0, condensado = 0, tapioca = 0, morango = 0, chocolate = 0;
    while (getline(cin, entrada))
    {
        stringstream ss(entrada);
        int gramas;

        ss >> gramas;
        ninho += gramas;

        ss >> gramas;
        condensado += gramas;

        ss >> gramas;
        tapioca += gramas;

        ss >> gramas;
        morango += gramas;

        ss >> gramas;
        chocolate += gramas;
    }

    unordered_map<string, int> ord;

    ord.insert(make_pair("NINHO", ninho));
    ord.insert(make_pair("CONDENSADO", condensado));
    ord.insert(make_pair("TAPIOCA", tapioca));
    ord.insert(make_pair("MORANGO", morango));
    ord.insert(make_pair("CHOCOLATE", chocolate));

    pair<string, int> maior = make_pair("", -99999);

    for (auto& p : ord)
    {
        if (p.second > maior.second) {
            maior = p;
        }
    }

    cout << maior.first << endl;

    return 0;
}